module polynomial_evaluation (
    input [3:0] a, // Coefficient a
    input [3:0] b, // Coefficient b
    input [3:0] c, // Coefficient c
    input [3:0] x, // Input x
    output [7:0] result // Result of P(x)
);
    wire [7:0] x_squared;
    wire [7:0] ax_squared;
    wire [7:0] bx;

  assign result = ax_squared + bx + c;
  assign bx = b * x;
  assign ax_squared = a * x_squared;
  assign x_squared = x * x;
endmodule
